import base64
import gzip
import pickle
import json
_WHITEBOX_BLOB = '' 
def load_whitebox_state():
    return pickle.loads(gzip.decompress(base64.b64decode(_WHITEBOX_BLOB)))

def whitebox_encrypt_block(block, p2, p3, p4, p5):
    state = list(block)
    perm = [0, 5, 10, 15, 4, 9, 14, 3, 8, 13, 2, 7, 12, 1, 6, 11]
    rounds = 2
    for r in range(rounds):
        state = [state[perm[i]] for i in range(16)]
        if r == rounds - 1: break
        mid_state = [0] * 16
        for col in range(4):
            t0, t1, t2, t3 = [p3[r][col*4 + i][state[col*4 + i]] for i in range(4)]
            for row in range(4):
                idx = col * 24 + row * 6
                sh_hi, sh_lo = 28 - (row * 8), 24 - (row * 8)
                x1_hi = p2[r][idx][(t0 >> sh_hi) & 0xF][(t1 >> sh_hi) & 0xF]
                x2_hi = p2[r][idx + 1][(t2 >> sh_hi) & 0xF][(t3 >> sh_hi) & 0xF]
                hi_val = p2[r][idx + 4][x1_hi][x2_hi]
                x1_lo = p2[r][idx + 2][(t0 >> sh_lo) & 0xF][(t1 >> sh_lo) & 0xF]
                x2_lo = p2[r][idx + 3][(t2 >> sh_lo) & 0xF][(t3 >> sh_lo) & 0xF]
                lo_val = p2[r][idx + 5][x1_lo][x2_lo]
                mid_state[col*4 + row] = ((hi_val << 4) | lo_val) & 0xFF
        new_state = [0] * 16
        for col in range(4):
            t0, t1, t2, t3 = [p5[r][col*4 + i][mid_state[col*4 + i]] for i in range(4)]
            for row in range(4):
                idx = col * 24 + row * 6
                sh_hi, sh_lo = 28 - (row * 8), 24 - (row * 8)
                x1_hi = p2[r][idx][(t0 >> sh_hi) & 0xF][(t1 >> sh_hi) & 0xF]
                x2_hi = p2[r][idx + 1][(t2 >> sh_hi) & 0xF][(t3 >> sh_hi) & 0xF]
                hi_val = p2[r][idx + 4][x1_hi][x2_hi]
                x1_lo = p2[r][idx + 2][(t0 >> sh_lo) & 0xF][(t1 >> sh_lo) & 0xF]
                x2_lo = p2[r][idx + 3][(t2 >> sh_lo) & 0xF][(t3 >> sh_lo) & 0xF]
                lo_val = p2[r][idx + 5][x1_lo][x2_lo]
                new_state[col*4 + row] = ((hi_val << 4) | lo_val) & 0xFF
        state = new_state
    for i in range(16): state[i] = p4[i][state[i]]
    return bytes(state)

def decrypt_logic(b64_payload, p2, p3, p4, p5):
    try:
        raw_bytes = list(base64.b64decode(b64_payload))
        iv = bytearray(raw_bytes[:16])
        ciphertext = raw_bytes[16:]
        decrypted_text = bytearray()
        keystream = None
        for j in range(len(ciphertext)):
            block_offset = j % 16
            if block_offset == 0:
                keystream = whitebox_encrypt_block(iv, p2, p3, p4, p5)
                for k in range(15, -1, -1):
                    iv[k] = (iv[k] + 1) & 0xFF
                    if iv[k] != 0: break
            decrypted_text.append(ciphertext[j] ^ keystream[block_offset])
        return decrypted_text.decode('utf-8')
    except: return None
def decrypt_npvt_config(file_bytes: bytes) -> dict | None:
    """Decrypt NPVT1 / NPVTSUB1 and return the Napsternet profile object."""
    try:
        raw_content = file_bytes.decode("utf-8", errors="ignore").strip()

        if raw_content.startswith("NPVTSUB1"):
            raw_content = raw_content[8:].strip()
        elif raw_content.startswith("NPVT1"):
            raw_content = raw_content[5:].strip()

        if not raw_content:
            return None

        p2, p3, p4, p5 = load_whitebox_state()
        payloads = raw_content.split(",")
        if len(payloads) < 2:
            return None

        decrypted_str = decrypt_logic(payloads[1], p2, p3, p4, p5)
        if not decrypted_str:
            return None

        try:
            result_json = json.loads(decrypted_str)
        except json.JSONDecodeError:
            return None
        if isinstance(result_json, list):
            if not result_json:
                return None
            first = result_json[0]
            return first if isinstance(first, dict) else None
        return result_json if isinstance(result_json, dict) else None
    except Exception:
        return None


def run(file_bytes: bytes) -> str | None:
    """Legacy helper: decrypt and return a human-readable dump."""
    result_json = decrypt_npvt_config(file_bytes)
    if not result_json:
        return None
    return json.dumps(result_json, indent=4, ensure_ascii=False)
